    end
    else if key = 'lcm' then
    begin
      ReadLCM;
    end
    else if key = 'pum_diag' then
    begin
      ReadBoolArray(tmpArr, 15);
      for li := 1 to 15 do
      begin
        for lj := 1 to 15 do
          PUM[li, lj] := false;
        PUM[li, li] := tmpArr[li];
      end;
    end;
    ReadComma;
  end;
  ReadObjectEnd;
end;

procedure WriteOutput;
var
  i, j: integer;
  s: string;
begin
  s := '{"cmv":[';
  for i := 1 to 15 do
  begin
    if CMV[i] then s := s + 'true' else s := s + 'false';
    if i < 15 then s := s + ',';
  end;
  s := s + '],"pum":[';
  for i := 1 to 15 do
  begin
    s := s + '[';
    for j := 1 to 15 do
    begin
      if PUM[i, j] then s := s + 'true' else s := s + 'false';
      if j < 15 then s := s + ',';
    end;
    s := s + ']';
    if i < 15 then s := s + ',';
  end;
  s := s + '],"fuv":[';
  for i := 1 to 15 do
  begin
    if FUV[i] then s := s + 'true' else s := s + 'false';
    if i < 15 then s := s + ',';
  end;
  s := s + '],"launch":';
  if LAUNCH then s := s + 'true' else s := s + 'false';
  s := s + '}';
  WriteLn(s);
end;

var
  i, j: integer;
  line: string;
begin
  InputBuf := '';
  while not EOF do
  begin
    ReadLn(line);
    InputBuf := InputBuf + line;
  end;
  InputPos := 1;

  ReadInput;

  DECIDE;

  WriteOutput;
end.

