  for i := 1 to 15 do
  begin
    Write('[');
    for j := 1 to 15 do
    begin
      if PUM[i, j] then Write('true') else Write('false');
      if j < 15 then Write(',');
    end;
    Write(']');
    if i < 15 then Write(',');
  end;
  Write('],"fuv":[');
  for i := 1 to 15 do
  begin
    if FUV[i] then Write('true') else Write('false');
    if i < 15 then Write(',');
  end;
  Write('],"launch":');
  if LAUNCH then Write('true') else Write('false');
  WriteLn('}');
end;

var
  i, j: integer;
  line: string;
  ch: char;
begin
  InputBuf := '';
  while not EOF(Input) do
  begin
    Read(Input, ch);
    InputBuf := InputBuf + ch;
  end;
  InputPos := 1;

  ReadInput;

  DECIDE;

  WriteOutput;
end.

